// ============================================================
// 1단계: 패키지명 추출만 담당 (HTTP 요청 없음)
// ============================================================

const llmText = $input.first().json.text || "";
const question = $('질문 1개씩 분리').first().json.questions || "";

const STOPWORDS = new Set([
  'the','and','for','this','that','with','your','from','are','can',
  'will','not','it','in','to','a','an','of','on','at','is','be',
  'or','if','as','by','we','do','so','up','no'
]);

const patterns = [
  /`([a-z][a-z0-9\-_.]{1,50})`/gi,
  /pip install\s+([a-z][a-z0-9\-_.]{1,50})/gi,
  /npm install\s+([a-z][a-z0-9\-_.@\/]{1,60})/gi,
];

const found = new Set();
for (const pat of patterns) {
  for (const m of llmText.matchAll(pat)) {
    const name = m[1].toLowerCase().replace(/_/g, '-').replace(/^@.*?\//, '');
    if (name.length > 2 && !STOPWORDS.has(name)) found.add(name);
  }
}

const packages = [...found].slice(0, 8);

return packages.map(pkg => ({
  json: { pkg, question, llmText }
}));

// ============================================================
// 2단계: 위험도 점수 계산 (HTTP 결과 기반)
// ============================================================

const POPULAR = [
  'numpy','pandas','requests','flask','django','fastapi','sqlalchemy',
  'pydantic','pytest','scipy','matplotlib','tensorflow','torch',
  'scikit-learn','transformers','boto3','celery','redis','pillow',
  'aiohttp','httpx','uvicorn','alembic','psycopg2','pymongo',
  'jinja2','click','typer','rich','pyyaml','python-dotenv',
  'langchain','openai','anthropic','cohere','huggingface-hub',
  'datasets','tokenizers','accelerate','sentence-transformers',
  'cryptography','paramiko','scapy','impacket',
  'beautifulsoup4','selenium','scrapy','lxml',
  'react','express','lodash','axios','webpack','babel',
  'eslint','typescript','jest','mocha','next','vue','angular'
];

function editDist(a, b) {
  const dp = Array.from({length: a.length+1}, (_,i) =>
    Array.from({length: b.length+1}, (_,j) => i===0?j:j===0?i:0));
  for (let i=1;i<=a.length;i++)
    for (let j=1;j<=b.length;j++)
      dp[i][j]=a[i-1]===b[j-1]?dp[i-1][j-1]:1+Math.min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]);
  return dp[a.length][b.length];
}

function detectConflation(name) {
  const parts = name.split(/[-_.]/).filter(p => p.length > 2);
  return parts.filter(p =>
    POPULAR.some(pk => pk===p || pk.startsWith(p) || p.startsWith(pk.split('-')[0]))
  );
}

const results = [];

for (const item of $input.all()) {
  const pkg      = item.json.pkg || '';
  const question = item.json.question || '';
  const llmText  = item.json.llmText || '';

  // PyPI / npm 응답 파싱
  const pypiStatus = item.json.statusCode || 404;
  const pypiBody   = item.json.body || {};
  const pypiExists = pypiStatus === 200;

  // npm 결과는 merge 되어 있지 않을 수 있어서 안전하게 처리
  let npmExists = false;

  let score = 0;
  const signals = [];
  let regDays = null;
  let versionCnt = 0;

  if (pypiExists) {
    const releases = pypiBody.releases || {};
    versionCnt = Object.keys(releases).length;
    const allFiles = Object.values(releases).flat();

    if (allFiles.length > 0) {
      const oldest = allFiles
        .map(f => new Date(f.upload_time))
        .sort((a, b) => a - b)[0];
      regDays = Math.floor((Date.now() - oldest) / 86400000);

      if      (regDays <  7) { score += 25; signals.push(`⚠️ 7일 이내 신규 등록 (${regDays}일 전)`); }
      else if (regDays < 30) { score += 15; signals.push(`⚠️ 30일 이내 등록 (${regDays}일 전)`); }
      else                   { signals.push(`✅ 등록 ${regDays}일 경과 (안정적)`); }
    }

    if (versionCnt === 1) { score += 10; signals.push(`⚠️ 배포 버전 1개뿐`); }
    else                  { signals.push(`✅ 버전 ${versionCnt}개 (활성 패키지)`); }

  } else {
    score += 55;
    signals.push(`🚨 PyPI 미등록 — 존재하지 않는 패키지`);
  }

  // 혼성형 탐지
  const parts = detectConflation(pkg);
  if (parts.length >= 2) {
    score += 20;
    signals.push(`⚠️ 합성 패턴 의심: [${parts.join(' + ')}]`);
  }

  // 편집 거리
  let minDist = 999, closest = '';
  for (const pk of POPULAR) {
    const d = editDist(pkg, pk);
    if (d < minDist) { minDist = d; closest = pk; }
  }
  if      (minDist > 0 && minDist <= 2) { score += 20; signals.push(`⚠️ '${closest}'과 매우 유사 (거리 ${minDist})`); }
  else if (minDist <= 4)                { score +=  8; signals.push(`ℹ️  '${closest}'과 유사 (거리 ${minDist})`); }

  const finalScore = Math.min(score, 100);
  const level = finalScore>=80?'CRITICAL':finalScore>=60?'HIGH':finalScore>=30?'MEDIUM':'LOW';
  const emoji = finalScore>=80?'🔴':finalScore>=60?'🟠':finalScore>=30?'🟡':'🟢';
  const color = finalScore>=80?'#c0392b':finalScore>=60?'#e67e22':finalScore>=30?'#d4ac0d':'#27ae60';

  results.push({ pkg, question, llmText, pypiExists, npmExists, score: finalScore, level, emoji, color, signals, closest, minDist, regDays, versionCnt });
}

return [{ json: { results } }];

// ============================================================
// 3단계: HTML 리포트 생성 → 파일로 저장
// ============================================================

const { results } = $input.first().json;
const question = results[0]?.question || '';
const llmText  = results[0]?.llmText  || '';
const now      = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });
const filename = `slop_report_${new Date().toISOString().slice(0,19).replace(/[:.]/g,'-')}.html`;

const summary = {
  critical: results.filter(r=>r.level==='CRITICAL').length,
  high:     results.filter(r=>r.level==='HIGH').length,
  medium:   results.filter(r=>r.level==='MEDIUM').length,
  low:      results.filter(r=>r.level==='LOW').length,
};
const maxScore = results.length > 0 ? Math.max(...results.map(r=>r.score)) : 0;
const overallLevel = maxScore>=80?'CRITICAL':maxScore>=60?'HIGH':maxScore>=30?'MEDIUM':'LOW';
const overallColor = maxScore>=80?'#c0392b':maxScore>=60?'#e67e22':maxScore>=30?'#d4ac0d':'#27ae60';
const overallEmoji = maxScore>=80?'🔴':maxScore>=60?'🟠':maxScore>=30?'🟡':'🟢';

const cards = results.map(r => `
  <div class="card" style="border-left:5px solid ${r.color}">
    <div class="card-header">
      <div class="pkg-name">${r.emoji} <code>${r.pkg}</code>
        <span class="badge" style="background:${r.color}">${r.level}</span>
        ${r.pypiExists
          ? `<span class="badge" style="background:#27ae60">PyPI ✅</span>`
          : `<span class="badge" style="background:#7f8c8d">PyPI ❌ 미등록</span>`}
        ${r.npmExists ? `<span class="badge" style="background:#e67e22">npm에는 존재</span>` : ''}
      </div>
      <div class="score" style="color:${r.color}">${r.score}<span style="font-size:14px;color:#999">/100</span></div>
    </div>
    <div class="progress-bar"><div style="width:${r.score}%;background:${r.color}"></div></div>
    <div class="signals">
      ${r.signals.map(s=>`<div class="signal">${s}</div>`).join('')}
      ${r.closest && r.minDist<=4 ? `<div class="hint">💡 유사 패키지 후보: <code>${r.closest}</code> (편집거리 ${r.minDist})</div>` : ''}
    </div>
  </div>`).join('');

const html = `<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>슬롭스쿼팅 탐지 리포트</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Malgun Gothic', -apple-system, sans-serif; background: #f0f2f5; color: #2c3e50; padding: 30px; }
  .wrap { max-width: 900px; margin: 0 auto; }
  .header { background: #1a252f; color: #fff; padding: 28px 32px; border-radius: 12px 12px 0 0; }
  .header h1 { font-size: 22px; margin-bottom: 6px; }
  .header p  { font-size: 13px; opacity: .65; }
  .overall { display: flex; justify-content: space-between; align-items: center;
             padding: 20px 32px; background: ${overallColor}18;
             border: 2px solid ${overallColor}; }
  .overall-left h2 { font-size: 26px; color: ${overallColor}; }
  .overall-left p  { font-size: 13px; color: #666; margin-top: 4px; }
  .overall-score   { font-size: 52px; font-weight: 900; color: ${overallColor}; line-height: 1; }
  .overall-score small { font-size: 14px; color: #999; display: block; text-align: right; }
  .summary { display: grid; grid-template-columns: repeat(4,1fr); background: #fff; padding: 20px 32px; gap: 12px; }
  .scard { text-align: center; padding: 14px; border-radius: 8px; }
  .scard .n { font-size: 32px; font-weight: 800; }
  .scard .l { font-size: 12px; font-weight: 700; margin-top: 4px; }
  .section { background: #fff; padding: 28px 32px; border-radius: 0 0 12px 12px; }
  .label { font-size: 12px; font-weight: 700; color: #95a5a6; margin-bottom: 8px; letter-spacing: .5px; }
  .question-box { background: #eaf0fb; border-left: 4px solid #2980b9; padding: 14px 18px; border-radius: 6px; margin-bottom: 20px; font-size: 15px; }
  .llm-box { background: #f9f9f9; border: 1px solid #e0e0e0; border-radius: 8px; padding: 16px; font-size: 13px; line-height: 1.8; color: #444; max-height: 180px; overflow-y: auto; white-space: pre-wrap; word-break: break-word; margin-bottom: 28px; }
  .results-title { font-size: 16px; font-weight: 700; margin-bottom: 16px; color: #2c3e50; }
  .card { border-radius: 10px; border: 1px solid #e8e8e8; padding: 20px; margin-bottom: 14px; }
  .card-header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 10px; }
  .pkg-name { font-size: 17px; font-weight: 700; display: flex; align-items: center; gap: 8px; flex-wrap: wrap; }
  .pkg-name code { font-family: monospace; font-size: 16px; background: #f0f0f0; padding: 2px 7px; border-radius: 4px; }
  .badge { font-size: 11px; color: #fff; padding: 3px 9px; border-radius: 10px; font-weight: 700; white-space: nowrap; }
  .score { font-size: 32px; font-weight: 900; line-height: 1; text-align: right; }
  .progress-bar { height: 8px; background: #ecf0f1; border-radius: 4px; overflow: hidden; margin-bottom: 14px; }
  .progress-bar div { height: 100%; border-radius: 4px; }
  .signals { display: flex; flex-direction: column; gap: 5px; }
  .signal { font-size: 13px; color: #444; padding: 5px 8px; background: #fafafa; border-radius: 4px; border-bottom: 1px solid #f0f0f0; }
  .hint { font-size: 12px; color: #7f8c8d; margin-top: 6px; padding-left: 4px; }
  .hint code { font-family: monospace; background: #f0f0f0; padding: 1px 5px; border-radius: 3px; }
  .footer { text-align: center; margin-top: 18px; font-size: 12px; color: #95a5a6; }
</style>
</head>
<body>
<div class="wrap">
  <div class="header">
    <h1>🛡️ AI 슬롭스쿼팅 탐지 리포트</h1>
    <p>생성 시각: ${now} | 분석 패키지: ${results.length}개</p>
  </div>

  <div class="overall">
    <div class="overall-left">
      <p style="font-size:13px;color:${overallColor};font-weight:700;">전체 위험도</p>
      <h2>${overallEmoji} ${overallLevel}</h2>
      <p>총 ${results.length}개 패키지 분석</p>
    </div>
    <div>
      <div class="overall-score">${maxScore}<small>최고 위험점수 / 100</small></div>
    </div>
  </div>

  <div class="summary">
    <div class="scard" style="background:#fdecea"><div class="n" style="color:#c0392b">${summary.critical}</div><div class="l" style="color:#c0392b">🔴 CRITICAL</div></div>
    <div class="scard" style="background:#fef5e7"><div class="n" style="color:#e67e22">${summary.high}</div><div class="l" style="color:#e67e22">🟠 HIGH</div></div>
    <div class="scard" style="background:#fefde7"><div class="n" style="color:#d4ac0d">${summary.medium}</div><div class="l" style="color:#d4ac0d">🟡 MEDIUM</div></div>
    <div class="scard" style="background:#eafaf1"><div class="n" style="color:#27ae60">${summary.low}</div><div class="l" style="color:#27ae60">🟢 LOW</div></div>
  </div>

  <div class="section">
    <div class="label">🙋 분석 요청 질문</div>
    <div class="question-box">${question}</div>
    <div class="label">🤖 LLM 원본 응답</div>
    <div class="llm-box">${llmText.replace(/</g,'&lt;').replace(/>/g,'&gt;')}</div>
    <div class="results-title">📦 패키지별 분석 결과</div>
    ${cards || '<p style="color:#95a5a6;text-align:center;padding:30px">패키지를 찾지 못했습니다.</p>'}
  </div>
  <div class="footer">슬롭스쿼팅 탐지기 v2 | Capstone Design | 분석 결과는 참고용이며 최종 판단은 직접 확인하세요.</div>
</div>
</body>
</html>`;

// n8n에서 바이너리 파일로 변환
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(html, 'utf-8'),
  filename,
  'text/html'
);

return [{
  json: { filename, summary, totalPackages: results.length },
  binary: { report: binaryData }
}];
